// app/restaurant/tasks/task.service.ts

import { Injectable } from '@angular/core';
import { BehaviorSubject, combineLatest, firstValueFrom, map, Observable } from 'rxjs';
import { BaseService } from './Base/base.service';
import { StaffUser, Task, TaskDetail, TaskRoleAssignment, TaskStatus, TaskSubtask, TaskSubtaskView, TaskUserAssignment, TaskView } from '../models';
import { StaffRole } from '../shared/guards/permission.service';

@Injectable({ providedIn: 'root' })
export class TaskService extends BaseService<Task> {

  protected getTableName(): string { return 'tasks'; }

  // ─── State aggiuntivo ──────────────────────────────────────────────────────
  private subtasksSubject = new BehaviorSubject<TaskSubtask[]>([]);
  private detailsSubject  = new BehaviorSubject<TaskDetail[]>([]);

  private roleAssignmentsSubject = new BehaviorSubject<TaskRoleAssignment[]>([]);
  private userAssignmentsSubject = new BehaviorSubject<TaskUserAssignment[]>([]);

  public roleAssignments$ = this.roleAssignmentsSubject.asObservable();
  public userAssignments$ = this.userAssignmentsSubject.asObservable();

  public subtasks$ = this.subtasksSubject.asObservable();
  public details$  = this.detailsSubject.asObservable();

  /**
   * Observable della gerarchia completa Task → Sotto-task → Dettagli.
   * Viene ricalcolato ogni volta che uno dei tre subject cambia.
   */
  public tasksView$: Observable<TaskView[]> = combineLatest([
    this.data$,
    this.subtasks$,
    this.details$,
    this.roleAssignments$,
    this.userAssignments$,
  ]).pipe(
    map(([tasks, subtasks, details, roleAssignments, userAssignments]) =>
      this.buildHierarchy(tasks, subtasks, details, roleAssignments, userAssignments)
    )
  );

  // ─── Override loadData (carica anche subtask e dettagli) ──────────────────
  override async loadData(additionalFilters?: Record<string, any>): Promise<void> {
    await super.loadData(additionalFilters);
    await Promise.all([
      this.loadSubtasks(),
      this.loadDetails(),
      this.loadRoleAssignments(),
      this.loadUserAssignments(),
    ]);
  }

  private async loadUserAssignments(): Promise<void> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) { this.userAssignmentsSubject.next([]); return; }
    // Carichiamo anche i dati dell'utente per comodità (nome/cognome)
    const { data, error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_user_assignments')
        .select(`
          *,
          user:users!task_user_assignments_user_id_fkey (
            id, first_name, last_name
          )
        `)
        .eq('restaurant_id', restaurantId)
    );
    if (!error) this.userAssignmentsSubject.next((data as any[]) ?? []);
  }

  // ─── Caricamento subtask ───────────────────────────────────────────────────
  private async loadSubtasks(): Promise<void> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) { this.subtasksSubject.next([]); return; }

    const { data, error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_subtasks')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .order('priority', { ascending: false })
    );
    if (!error) this.subtasksSubject.next((data as TaskSubtask[]) ?? []);
  }

  private async loadRoleAssignments(): Promise<void> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) { this.roleAssignmentsSubject.next([]); return; }
    const { data, error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_role_assignments')
        .select('*')
        .eq('restaurant_id', restaurantId)
    );
    if (!error) this.roleAssignmentsSubject.next((data as TaskRoleAssignment[]) ?? []);
  }

  // ─── Caricamento dettagli ──────────────────────────────────────────────────
  private async loadDetails(): Promise<void> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) { this.detailsSubject.next([]); return; }

    const { data, error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_details')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .order('created_at', { ascending: true })
    );
    if (!error) this.detailsSubject.next((data as TaskDetail[]) ?? []);
  }

  // ─── Costruzione gerarchia ─────────────────────────────────────────────────
  private buildHierarchy(
    tasks: Task[],
    subtasks: TaskSubtask[],
    details: TaskDetail[],
    roleAssignments: TaskRoleAssignment[],
    userAssignments: any[]
  ): TaskView[] {
    return tasks.map(task => {
      // Assegnazioni a livello di task
      const assignedRoles = roleAssignments
        .filter(ra => ra.task_id === task.id)
        .map(ra => ra.role);

      const assignedUsers = userAssignments
        .filter(ua => ua.task_id === task.id)
        .map(ua => ({
          id: ua.user_id,
          firstName: ua.user?.first_name || '',
          lastName: ua.user?.last_name || ''
        }));

      // Sotto-task
      const taskSubtasks = subtasks
        .filter(s => s.task_id === task.id)
        .sort((a, b) => b.priority - a.priority);

      // Costruisci subtask con dettagli
      const subtaskViews: TaskSubtaskView[] = taskSubtasks.map(sub => {
        const subDetails = details.filter(d => d.subtask_id === sub.id);
        const hasDetails = subDetails.length > 0;
        const totalDetails = subDetails.length;
        const completedDetails = subDetails.filter(d => d.completed).length;
        const progress = hasDetails ? Math.round((completedDetails / totalDetails) * 100) : 0;
        const status: TaskStatus = hasDetails
          ? this.computeSubtaskStatus(completedDetails, totalDetails)
          : sub.status;

        return {
          ...sub,
          details: subDetails,
          hasDetails,
          progress,
          status,
          completedDetails,
          totalDetails,
        };
      });

      // Metriche task
      const totalSubtasks = subtaskViews.length;
      const completedSubtasks = subtaskViews.filter(s => s.status === 'completata').length;
      const allDetails = subtaskViews.flatMap(s => s.details);
      const totalDetails = allDetails.length;
      const completedDetails = allDetails.filter(d => d.completed).length;
      const progress = this.computeTaskProgress(subtaskViews);
      const status = this.computeTaskStatus(subtaskViews);

      return {
        ...task,
        subtasks: subtaskViews,
        progress,
        status,
        completedSubtasks,
        totalSubtasks,
        completedDetails,
        totalDetails,
        assignedRoles,
        assignedUsers,
      };
    });
  }

  // ─── Calcolo automatico status ─────────────────────────────────────────────
  private computeSubtaskStatus(completed: number, total: number): TaskStatus {
    if (total === 0 || completed === 0) return 'da_iniziare';
    if (completed === total)            return 'completata';
    return 'in_lavorazione';
  }

  private computeTaskStatus(subtasks: TaskSubtaskView[]): TaskStatus {
    if (subtasks.length === 0)                         return 'da_iniziare';
    if (subtasks.every(s => s.status === 'completata')) return 'completata';
    if (subtasks.some(s => s.status !== 'da_iniziare')) return 'in_lavorazione';
    return 'da_iniziare';
  }

  private computeTaskProgress(subtasks: TaskSubtaskView[]): number {
    if (subtasks.length === 0) return 0;
    const totalWeight = subtasks.reduce((acc, s) => {
      if (s.status === 'completata')    return acc + 1;
      if (s.status === 'in_lavorazione')
        return acc + (s.hasDetails ? s.progress / 100 : 0.5);
      return acc;
    }, 0);
    return Math.round((totalWeight / subtasks.length) * 100);
  }

  // ─── CRUD Sotto-task ────────────────────────────────────────────────────────
  async createSubtask(payload: Partial<TaskSubtask>): Promise<TaskSubtask | null> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return null;

    const { data, error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_subtasks')
        .insert({
          ...payload,
          restaurant_id: restaurantId,
          status: 'da_iniziare',
          created_at: new Date().toISOString(),
          updated_at: new Date().toISOString(),
        })
        .select()
        .single()
    );
    if (error) { this.handleError('createSubtask', error); return null; }
    await this.loadSubtasks();
    if (!data) return null;
    return data as TaskSubtask;
  }

  async updateSubtask(id: string, updates: Partial<TaskSubtask>): Promise<boolean> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;

    const { error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_subtasks')
        .update({ ...updates, updated_at: new Date().toISOString() })
        .eq('id', id)
        .eq('restaurant_id', restaurantId)
    );
    if (error) { this.handleError('updateSubtask', error); return false; }
    await this.loadSubtasks();
    return true;
  }

  async deleteSubtask(id: string): Promise<boolean> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;

    // I dettagli vengono eliminati a cascata dal DB, ma gestiamo anche lato client
    const { error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_subtasks')
        .delete()
        .eq('id', id)
        .eq('restaurant_id', restaurantId)
    );
    if (error) { this.handleError('deleteSubtask', error); return false; }
    await Promise.all([this.loadSubtasks(), this.loadDetails()]);
    return true;
  }

  // ─── CRUD Dettagli ─────────────────────────────────────────────────────────
  async createDetail(payload: Partial<TaskDetail>): Promise<TaskDetail | null> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return null;

    const { data, error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_details')
        .insert({
          ...payload,
          restaurant_id: restaurantId,
          completed: false,
          created_at: new Date().toISOString(),
          updated_at: new Date().toISOString(),
        })
        .select()
        .single()
    );
    if (error) { this.handleError('createDetail', error); return null; }
    await this.loadDetails();
    if (!data) return null;
    return data as TaskDetail;
  }

  async updateDetail(id: string, updates: Partial<TaskDetail>): Promise<boolean> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;

    const { error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_details')
        .update({ ...updates, updated_at: new Date().toISOString() })
        .eq('id', id)
        .eq('restaurant_id', restaurantId)
    );
    if (error) { this.handleError('updateDetail', error); return false; }
    await this.loadDetails();
    return true;
  }

  async deleteDetail(id: string): Promise<boolean> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;

    const { error } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_details')
        .delete()
        .eq('id', id)
        .eq('restaurant_id', restaurantId)
    );
    if (error) { this.handleError('deleteDetail', error); return false; }
    await this.loadDetails();
    return true;
  }

  // ─── Helper copy ───────────────────────────────────────────────────────────
  buildTaskCopyText(task: TaskView): string {
    const lines: string[] = [`📋 TASK: ${task.title}`];
    if (task.notes) lines.push(`Note: ${task.notes}`);
    lines.push('');
    task.subtasks.forEach(sub => {
      const check = sub.status === 'completata' ? '✓' : '○';
      lines.push(`${check} ${sub.name}`);
      sub.details.forEach(d =>
        lines.push(`  ${d.completed ? '✓' : '–'} ${d.name}`)
      );
    });
    return lines.join('\n');
  }

  buildSubtaskCopyText(sub: TaskSubtaskView): string {
    const lines: string[] = [`○ ${sub.name}`];
    sub.details.forEach(d =>
      lines.push(`  ${d.completed ? '✓' : '–'} ${d.name}`)
    );
    return lines.join('\n');
  }
  
async getStaffUsers(): Promise<StaffUser[]> {
  const restaurantId = await this.getCurrentRestaurantId();
  if (!restaurantId) return [];

  const { data, error } = await this.run(
    this.getSupabaseClientPublic()
      .from('restaurant_staff')
      .select(`
        user_id,
        role,
        user:user_id (
          id,
          first_name,
          last_name,
          email
        )
      `)
      .eq('restaurant_id', restaurantId)
      .eq('invitation_status', 'accepted')
  );

  if (error || !data) {
    console.error('Error loading staff users:', error);
    return [];
  }

  return data.map((item: any) => {
    const userData = item.user;
    return {
      id: item.user_id,
      user_id: item.user_id,
      first_name: userData?.first_name || '',
      last_name: userData?.last_name || '',
      email: userData?.email || '',
      role: item.role,
    };
  });
}

async createTaskWithAssignments(
  taskData: Partial<Task>,
  assignedRoles: StaffRole[],
  assignedUserIds: string[]
): Promise<TaskView | null> {
  const restaurantId = await this.getCurrentRestaurantId();
  if (!restaurantId) return null;

  // 1. Crea la task base
  const task = await this.create({
    ...taskData,
    assigned_role: null
  });
  if (!task) return null;

  // 2. Inserisci assegnazioni ruoli
  if (assignedRoles.length > 0) {
    const roleInserts = assignedRoles.map(role => ({
      task_id: task.id,
      role,
      restaurant_id: restaurantId,
    }));
    const { error: roleError } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_role_assignments')
        .insert(roleInserts)
    );
    if (roleError) {
      await this.delete(task.id);
      return null;
    }
  }

  // 3. Inserisci assegnazioni utenti
  if (assignedUserIds.length > 0) {
    const userInserts = assignedUserIds.map(userId => ({
      task_id: task.id,
      user_id: userId,
      restaurant_id: restaurantId,
    }));
    const { error: userError } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_user_assignments')
        .insert(userInserts)
    );
    if (userError) {
      await this.delete(task.id); // grazie a ON DELETE CASCADE elimina anche le assign ruoli
      return null;
    }
  }

  // Ricarica i dati
  await Promise.all([
    this.loadData(),
    this.loadRoleAssignments(),
    this.loadUserAssignments()
  ]);

  const tasksView = await firstValueFrom(this.tasksView$);
  return tasksView.find(t => t.id === task.id) || null;
}

async updateTaskWithAssignments(
  id: string,
  taskData: Partial<Task>,
  assignedRoles: StaffRole[],
  assignedUserIds: string[]
): Promise<boolean> {
  const restaurantId = await this.getCurrentRestaurantId();
  if (!restaurantId) return false;

  // 1. Aggiorna la task base
  const updateSuccess = await this.update(id, { ...taskData, assigned_role: null });
  if (!updateSuccess) return false;

  // 2. Sostituisci ruoli
  const { error: deleteRolesError } = await this.run(
    this.getSupabaseClientPublic()
      .from('task_role_assignments')
      .delete()
      .eq('task_id', id)
  );
  if (deleteRolesError) return false;

  if (assignedRoles.length > 0) {
    const roleInserts = assignedRoles.map(role => ({
      task_id: id,
      role,
      restaurant_id: restaurantId,
    }));
    const { error: insertRolesError } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_role_assignments')
        .insert(roleInserts)
    );
    if (insertRolesError) return false;
  }

  // 3. Sostituisci utenti
  const { error: deleteUsersError } = await this.run(
    this.getSupabaseClientPublic()
      .from('task_user_assignments')
      .delete()
      .eq('task_id', id)
  );
  if (deleteUsersError) return false;

  if (assignedUserIds.length > 0) {
    const userInserts = assignedUserIds.map(userId => ({
      task_id: id,
      user_id: userId,
      restaurant_id: restaurantId,
    }));
    const { error: insertUsersError } = await this.run(
      this.getSupabaseClientPublic()
        .from('task_user_assignments')
        .insert(userInserts)
    );
    if (insertUsersError) return false;
  }

  await Promise.all([
    this.loadData(),
    this.loadRoleAssignments(),
    this.loadUserAssignments()
  ]);
  return true;
}

isTaskVisibleForUser(
  task: TaskView,
  userId: string,
  userRole: StaffRole | null,
  isOwnerOrManager: boolean
): boolean {
  if (isOwnerOrManager) return true;

  // Assegnazione diretta a utente
  if (task.assignedUsers.some(u => u.id === userId)) return true;

  // Assegnazione a ruolo
  if (userRole && task.assignedRoles.includes(userRole)) return true;

  // Retrocompatibilità: campo assigned_role singolo
  if (task.assigned_role && task.assigned_role !== 'tutti') {
    return task.assigned_role === userRole;
  }

  // Vecchio 'tutti' o task senza restrizioni
  if (task.assigned_role === 'tutti') return true;
  if (task.assigned_role === null && task.assignedRoles.length === 0 && task.assignedUsers.length === 0) {
    return true;
  }

  return false;
}

async getTemplates(): Promise<TaskView[]> {
  const restaurantId = await this.getCurrentRestaurantId();
  if (!restaurantId) return [];

  // Filtra le task con is_template = true
  const allTasks = await firstValueFrom(this.tasksView$);
  return allTasks.filter(task => task.is_template);
}

async saveAsTemplate(taskId: string, templateName: string): Promise<TaskView | null> {
  const restaurantId = await this.getCurrentRestaurantId();
  if (!restaurantId) return null;

  // 1. Recupera la task originale con tutti i suoi dati
  const originalTask = (await firstValueFrom(this.tasksView$))
    .find(t => t.id === taskId);
  if (!originalTask) return null;

  // 2. Crea una nuova task copiando i campi base, ma con is_template = true
  const newTaskData: Partial<Task> = {
    title: originalTask.title,
    notes: originalTask.notes,
    priority: originalTask.priority,
    association_type: originalTask.association_type,
    client_name: originalTask.client_name,
    due_date: originalTask.due_date,
    assigned_role: null, // i template usano le tabelle di assign
    is_template: true,
    template_name: templateName,
  };

  // 3. Crea la task base
  const newTask = await this.create(newTaskData);
  if (!newTask) return null;

  // 4. Copia i subtask
  for (const sub of originalTask.subtasks) {
    const newSubtask = await this.createSubtask({
      task_id: newTask.id,
      name: sub.name,
      priority: sub.priority,
      due_date: sub.due_date,
    });
    if (!newSubtask) {
      // Fallback: elimina la task creata e i subtask già inseriti
      await this.delete(newTask.id);
      return null;
    }

    // 5. Copia i dettagli di ogni subtask
    for (const detail of sub.details) {
      await this.createDetail({
        subtask_id: newSubtask.id,
        name: detail.name,
        notes: detail.notes,
        due_date: detail.due_date,
      });
    }
  }

  // 6. Copia le assegnazioni ruoli
  const roleAssignments = await this.getRoleAssignmentsForTask(taskId);
  if (roleAssignments.length > 0) {
    const roleInserts = roleAssignments.map(ra => ({
      task_id: newTask.id,
      role: ra.role,
      restaurant_id: restaurantId,
    }));
    await this.run(
      this.getSupabaseClientPublic()
        .from('task_role_assignments')
        .insert(roleInserts)
    );
  }

  // 7. Copia le assegnazioni utenti
  const userAssignments = await this.getUserAssignmentsForTask(taskId);
  if (userAssignments.length > 0) {
    const userInserts = userAssignments.map(ua => ({
      task_id: newTask.id,
      user_id: ua.user_id,
      restaurant_id: restaurantId,
    }));
    await this.run(
      this.getSupabaseClientPublic()
        .from('task_user_assignments')
        .insert(userInserts)
    );
  }

  // Ricarica i dati
  await Promise.all([
    this.loadData(),
    this.loadSubtasks(),
    this.loadDetails(),
    this.loadRoleAssignments(),
    this.loadUserAssignments(),
  ]);

  // Restituisci la nuova task view
  const updatedTasks = await firstValueFrom(this.tasksView$);
  return updatedTasks.find(t => t.id === newTask.id) || null;
}

private async getRoleAssignmentsForTask(taskId: string): Promise<TaskRoleAssignment[]> {
  const { data, error } = await this.run(
    this.getSupabaseClientPublic()
      .from('task_role_assignments')
      .select('*')
      .eq('task_id', taskId)
  );
  return error ? [] : (data as TaskRoleAssignment[]);
}

private async getUserAssignmentsForTask(taskId: string): Promise<TaskUserAssignment[]> {
  const { data, error } = await this.run(
    this.getSupabaseClientPublic()
      .from('task_user_assignments')
      .select('*')
      .eq('task_id', taskId)
  );
  return error ? [] : (data as TaskUserAssignment[]);
}

async createFromTemplate(templateId: string): Promise<TaskView | null> {
  const restaurantId = await this.getCurrentRestaurantId();
  if (!restaurantId) return null;

  // Recupera il template
  const template = (await firstValueFrom(this.tasksView$))
    .find(t => t.id === templateId && t.is_template);
  if (!template) return null;

  // Crea una nuova task copiando i campi base, ma con is_template = false
  const newTaskData: Partial<Task> = {
    title: template.title,
    notes: template.notes,
    priority: template.priority,
    association_type: template.association_type,
    client_name: template.client_name,
    due_date: template.due_date,
    assigned_role: null,
    is_template: false,
  };

  const newTask = await this.create(newTaskData);
  if (!newTask) return null;

  // Copia subtask e dettagli (stessa logica di saveAsTemplate)
  for (const sub of template.subtasks) {
    const newSubtask = await this.createSubtask({
      task_id: newTask.id,
      name: sub.name,
      priority: sub.priority,
      due_date: sub.due_date,
    });
    if (!newSubtask) {
      await this.delete(newTask.id);
      return null;
    }
    for (const detail of sub.details) {
      await this.createDetail({
        subtask_id: newSubtask.id,
        name: detail.name,
        notes: detail.notes,
        due_date: detail.due_date,
      });
    }
  }

  // Copia assegnazioni
  const roleAssignments = await this.getRoleAssignmentsForTask(templateId);
  if (roleAssignments.length > 0) {
    const roleInserts = roleAssignments.map(ra => ({
      task_id: newTask.id,
      role: ra.role,
      restaurant_id: restaurantId,
    }));
    await this.run(
      this.getSupabaseClientPublic()
        .from('task_role_assignments')
        .insert(roleInserts)
    );
  }

  const userAssignments = await this.getUserAssignmentsForTask(templateId);
  if (userAssignments.length > 0) {
    const userInserts = userAssignments.map(ua => ({
      task_id: newTask.id,
      user_id: ua.user_id,
      restaurant_id: restaurantId,
    }));
    await this.run(
      this.getSupabaseClientPublic()
        .from('task_user_assignments')
        .insert(userInserts)
    );
  }

  // Ricarica dati
  await Promise.all([
    this.loadData(),
    this.loadSubtasks(),
    this.loadDetails(),
    this.loadRoleAssignments(),
    this.loadUserAssignments(),
  ]);

  const updatedTasks = await firstValueFrom(this.tasksView$);
  return updatedTasks.find(t => t.id === newTask.id) || null;
}

}